    while (!q.empty()) {
        vector<int> curLevel;
        int size = q.size();

        for (int i = 0; i < size; i++)
        {
            TreeNode *cur = q.front();
            q.pop();
            curLevel.push_back(cur->val);
            if (cur->left) q.push(cur->left);
            if (cur->right) q.push(cur->right);
        }
        ret.push_back(curLevel);
    }
    return ret;
}
