// 1->2->3->4 则返回 3；1->2->3 则返回 2
ListNode* middleNode(ListNode* head) {
    ListNode *fast = head, *slow = head;

    while (fast && fast->next)
    {
        slow = slow->next;
        fast = fast->next->next;
    }

    return slow;
}
